// SQLite store for the third-brain index
// Wraps Node's built-in node:sqlite — FTS5 search on markdown content

import { DatabaseSync } from "node:sqlite";
import { mkdirSync, existsSync } from "node:fs";
import { dirname } from "node:path";
import type { IndexedFile, SearchResult } from "./types.js";

export class BrainStore {
  private db: DatabaseSync;
  private hasFTS5 = false;

  constructor(dbPath: string) {
    const dir = dirname(dbPath);
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

    this.db = new DatabaseSync(dbPath);
    this.db.exec("PRAGMA journal_mode = WAL");
    this.db.exec("PRAGMA busy_timeout = 5000");
    this.migrate();
  }

  private migrate(): void {
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS files (
        path TEXT PRIMARY KEY,
        checksum TEXT NOT NULL,
        type TEXT NOT NULL,
        tags TEXT NOT NULL DEFAULT '',
        title TEXT NOT NULL DEFAULT '',
        content TEXT NOT NULL DEFAULT '',
        updated TEXT NOT NULL DEFAULT '',
        indexed_at TEXT NOT NULL DEFAULT (datetime('now'))
      );
    `);

    // Try FTS5 — fall back to substring if unavailable
    try {
      this.db.exec(`
        CREATE VIRTUAL TABLE IF NOT EXISTS files_fts USING fts5(
          path, title, content, tags,
          content='files', content_rowid='rowid'
        );

        CREATE TRIGGER IF NOT EXISTS files_ai AFTER INSERT ON files BEGIN
          INSERT INTO files_fts(rowid, path, title, content, tags)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_ad AFTER DELETE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
        END;
        CREATE TRIGGER IF NOT EXISTS files_au AFTER UPDATE ON files BEGIN
          INSERT INTO files_fts(files_fts, rowid, path, title, content, tags)
          VALUES('delete', old.rowid, old.path, old.title, old.content, old.tags);
          INSERT INTO files_fts(rowid, path, title, content, tags)
          VALUES (new.rowid, new.path, new.title, new.content, new.tags);
        END;
      `);
      this.hasFTS5 = true;
    } catch {
      this.hasFTS5 = false;
    }
  }

  // ─── File operations ──────────────────────────────────────────────

  upsertFile(file: IndexedFile): void {
    this.db.prepare(`
      INSERT INTO files (path, checksum, type, tags, title, content, updated, indexed_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, datetime('now'))
      ON CONFLICT(path) DO UPDATE SET
        checksum = excluded.checksum,
        type = excluded.type,
        tags = excluded.tags,
        title = excluded.title,
        content = excluded.content,
        updated = excluded.updated,
        indexed_at = datetime('now')
    `).run(
      file.path || "",
      file.checksum || "",
      file.type || "unknown",
      file.tags || "",
      file.title || "",
      file.content || "",
      file.updated || ""
    );
  }

  getFile(path: string): IndexedFile | undefined {
    return this.db.prepare("SELECT * FROM files WHERE path = ?").get(path) as IndexedFile | undefined;
  }

  deleteFile(path: string): boolean {
    const result = this.db.prepare("DELETE FROM files WHERE path = ?").run(path);
    return result.changes > 0;
  }

  listFiles(type?: string): IndexedFile[] {
    if (type) {
      return this.db.prepare("SELECT * FROM files WHERE type = ? ORDER BY updated DESC")
        .all(type) as IndexedFile[];
    }
    return this.db.prepare("SELECT * FROM files ORDER BY updated DESC").all() as IndexedFile[];
  }

  // ─── Search ────────────────────────────────────────────────────────

  search(query: string, limit = 10): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) return [];

    if (this.hasFTS5) {
      return this._searchFTS(query, limit);
    }
    return this._searchFallback(query, limit);
  }

  searchByType(query: string, type: string, limit = 10): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    if (terms.length === 0) {
      return this.listFiles(type).map(f => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score: 1,
      }));
    }

    if (this.hasFTS5) {
      return this._searchFTS(query, limit, type);
    }
    return this._searchFallback(query, limit, type);
  }

  searchByTag(tag: string, limit = 50): SearchResult[] {
    const files = this.db.prepare(
      "SELECT * FROM files WHERE tags LIKE ? ORDER BY updated DESC LIMIT ?"
    ).all(`%${tag}%`, limit) as IndexedFile[];

    return files.map(f => ({
      file: f.path,
      type: f.type,
      tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
      title: f.title,
      excerpt: f.content.slice(0, 200),
      score: 1,
    }));
  }

  private _searchFTS(query: string, limit: number, type?: string): SearchResult[] {
    const terms = query.trim().split(/\s+/).filter(Boolean);
    const ftsQuery = terms.map(t => `"${t.replace(/"/g, '""')}"`).join(" OR ");

    let sql = `
      SELECT f.path, f.type, f.tags, f.title,
             substr(f.content, 1, 200) as excerpt,
             bm25(files_fts) as score
      FROM files f
      JOIN files_fts ft ON f.rowid = ft.rowid
      WHERE files_fts MATCH ?
    `;
    const params: unknown[] = [ftsQuery];

    if (type) {
      sql += " AND f.type = ?";
      params.push(type);
    }

    sql += " ORDER BY score LIMIT ?";
    params.push(limit);

    try {
      const rows = this.db.prepare(sql).all(...params) as Array<Record<string, unknown>>;
      return rows.map(r => ({
        file: r.path as string,
        type: r.type as string,
        tags: (r.tags as string) ? (r.tags as string).split(",").filter(Boolean) : [],
        title: r.title as string,
        excerpt: r.excerpt as string,
        score: r.score as number,
      }));
    } catch {
      return this._searchFallback(query, limit, type);
    }
  }

  private _searchFallback(query: string, limit: number, type?: string): SearchResult[] {
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    const files = type
      ? this.db.prepare("SELECT * FROM files WHERE type = ?").all(type) as IndexedFile[]
      : this.db.prepare("SELECT * FROM files").all() as IndexedFile[];

    return files
      .map(f => {
        const text = `${f.path} ${f.title} ${f.content} ${f.tags}`.toLowerCase();
        const matches = terms.filter(t => text.includes(t)).length;
        return { file: f, score: matches / terms.length };
      })
      .filter(({ score }) => score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, limit)
      .map(({ file: f, score }) => ({
        file: f.path,
        type: f.type,
        tags: f.tags ? f.tags.split(",").filter(Boolean) : [],
        title: f.title,
        excerpt: f.content.slice(0, 200),
        score,
      }));
  }

  // ─── Stats ─────────────────────────────────────────────────────────

  stats(): { files: number; types: Record<string, number> } {
    const count = this.db.prepare("SELECT COUNT(*) as c FROM files").get() as { c: number };
    const typeRows = this.db.prepare(
      "SELECT type, COUNT(*) as c FROM files GROUP BY type"
    ).all() as Array<{ type: string; c: number }>;

    const types: Record<string, number> = {};
    for (const row of typeRows) {
      types[row.type] = row.c;
    }

    return { files: count.c, types };
  }

  // ─── Lifecycle ─────────────────────────────────────────────────────

  close(): void {
    this.db.close();
  }
}

// Shared types for the third-brain system

export type BrainFileType = "daily" | "person" | "projects" | "patterns" | "sessions" | "self";

export interface BrainFileFrontmatter {
  type: BrainFileType;
  tags: string[];
  updated?: string;
  date?: string;
  name?: string;
  status?: string;
  confidence?: string;
}

export interface BrainFile {
  /** Path relative to brain/ directory */
  path: string;
  /** Full absolute path */
  absolutePath: string;
  /** Parsed frontmatter */
  frontmatter: BrainFileFrontmatter;
  /** Markdown content (below frontmatter) */
  content: string;
  /** Raw file content */
  raw: string;
  /** SHA-256 checksum for change detection */
  checksum: string;
}

export interface IndexedFile {
  path: string;
  checksum: string;
  type: string;
  tags: string;
  title: string;
  content: string;
  updated: string;
  indexed_at: string;
}

export interface SearchResult {
  file: string;
  type: string;
  tags: string[];
  title: string;
  excerpt: string;
  score: number;
}

export interface MemoryInput {
  type: BrainFileType;
  file: string;
  section?: string;
  content: string;
  tags: string[];
}

export interface DedupReport {
  duplicates: Array<{
    type: "exact" | "near" | "stale" | "conflict";
    files: string[];
    excerpt: string;
    suggestion: string;
  }>;
  stats: {
    totalEntries: number;
    duplicateGroups: number;
    staleEntries: number;
    conflicts: number;
  };
}

// Markdown file read/write helpers for the third-brain
// Handles YAML frontmatter parsing and content manipulation

import { readFileSync, writeFileSync, existsSync, mkdirSync } from "node:fs";
import { readdir, stat } from "node:fs/promises";
import { join, dirname, relative } from "node:path";
import { createHash } from "node:crypto";
import matter from "gray-matter";
import type { BrainFile, BrainFileFrontmatter } from "./types.js";

const BRAIN_DIR = join(import.meta.dirname, "..", "brain");

export function brainPath(relativePath: string): string {
  return join(BRAIN_DIR, relativePath);
}

export function relativeBrainPath(absolutePath: string): string {
  return relative(BRAIN_DIR, absolutePath);
}

// ─── Reading ──────────────────────────────────────────────────────────

export function readBrainFile(relativePath: string): BrainFile | null {
  const absPath = brainPath(relativePath);
  if (!existsSync(absPath)) return null;

  const raw = readFileSync(absPath, "utf-8");
  const parsed = matter(raw);
  const frontmatter = (parsed.data || {}) as BrainFileFrontmatter;

  return {
    path: relativePath,
    absolutePath: absPath,
    frontmatter,
    content: parsed.content,
    raw,
    checksum: createHash("sha256").update(raw).digest("hex").slice(0, 16),
  };
}

export async function scanBrainFiles(): Promise<BrainFile[]> {
  const files: BrainFile[] = [];
  await scanDir(BRAIN_DIR, files);
  return files;
}

async function scanDir(dir: string, files: BrainFile[]): Promise<void> {
  if (!existsSync(dir)) return;

  const entries = await readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      // Skip special directories
      if (entry.name.startsWith("_") || entry.name === "templates") continue;
      await scanDir(fullPath, files);
    } else if (entry.isFile() && entry.name.endsWith(".md")) {
      const relPath = relativeBrainPath(fullPath);
      const file = readBrainFile(relPath);
      if (file) files.push(file);
    }
  }
}

// ─── Writing ──────────────────────────────────────────────────────────

export function writeBrainFile(
  relativePath: string,
  frontmatter: BrainFileFrontmatter,
  content: string
): string {
  const absPath = brainPath(relativePath);
  const dir = dirname(absPath);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });

  const raw = matter.stringify(content, frontmatter as Record<string, unknown>);
  writeFileSync(absPath, raw, "utf-8");

  return createHash("sha256").update(raw).digest("hex").slice(0, 16);
}

/**
 * Append a bullet point to a specific section in a markdown file.
 * Creates the file from template if it doesn't exist.
 */
export function appendToSection(
  relativePath: string,
  section: string,
  bullet: string,
  frontmatter?: BrainFileFrontmatter
): BrainFile {
  let file = readBrainFile(relativePath);

  if (!file) {
    // Create from scratch
    const defaultFm: BrainFileFrontmatter = frontmatter || {
      type: "daily",
      tags: [],
      updated: today(),
    };
    const content = `\n## ${section}\n\n- ${bullet}\n`;
    writeBrainFile(relativePath, defaultFm, content);
    return readBrainFile(relativePath)!;
  }

  // Find the section heading
  const lines = file.content.split("\n");
  const sectionHeading = `## ${section}`;
  let sectionIndex = -1;

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim() === sectionHeading) {
      sectionIndex = i;
      break;
    }
  }

  if (sectionIndex === -1) {
    // Section doesn't exist — append it at the end
    const newContent = file.content.trimEnd() + `\n\n## ${section}\n\n- ${bullet}\n`;
    const checksum = writeBrainFile(relativePath, {
      ...file.frontmatter,
      updated: today(),
    }, newContent);
    return readBrainFile(relativePath)!;
  }

  // Check if bullet already exists (avoid exact duplicates)
  const bulletText = bullet.trim();
  for (let i = sectionIndex + 1; i < lines.length; i++) {
    if (lines[i].startsWith("## ")) break; // next section
    if (lines[i].trim() === `- ${bulletText}`) {
      return file; // Already exists, no change
    }
  }

  // Insert the bullet after the section heading, before the next section or end
  let insertIndex = sectionIndex + 1;
  // Skip blank lines after heading
  while (insertIndex < lines.length && lines[insertIndex].trim() === "") {
    insertIndex++;
  }

  lines.splice(insertIndex, 0, `- ${bulletText}`);
  const newContent = lines.join("\n");

  writeBrainFile(relativePath, {
    ...file.frontmatter,
    updated: today(),
  }, newContent);

  return readBrainFile(relativePath)!;
}

/**
 * Remove a line matching a pattern from a section.
 */
export function removeFromSection(
  relativePath: string,
  section: string,
  match: string
): BrainFile | null {
  const file = readBrainFile(relativePath);
  if (!file) return null;

  const lines = file.content.split("\n");
  const sectionHeading = `## ${section}`;
  let sectionIndex = -1;
  let removed = false;

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim() === sectionHeading) {
      sectionIndex = i;
      continue;
    }
    if (sectionIndex >= 0 && lines[i].startsWith("## ")) break;
    if (sectionIndex >= 0 && lines[i].toLowerCase().includes(match.toLowerCase())) {
      lines.splice(i, 1);
      i--; // adjust index after splice
      removed = true;
    }
  }

  if (!removed) return file;

  writeBrainFile(relativePath, {
    ...file.frontmatter,
    updated: today(),
  }, lines.join("\n"));

  return readBrainFile(relativePath)!;
}

// ─── Templates ────────────────────────────────────────────────────────

const TEMPLATES_DIR = join(import.meta.dirname, "..", "templates");

export function loadTemplate(type: string): string {
  const templatePath = join(TEMPLATES_DIR, `${type}.md`);
  if (existsSync(templatePath)) {
    return readFileSync(templatePath, "utf-8");
  }
  return "";
}

// ─── Helpers ──────────────────────────────────────────────────────────

export function today(): string {
  return new Date().toISOString().slice(0, 10);
}

/** Convert a Date object or string to YYYY-MM-DD string */
export function dateToString(value: unknown): string {
  if (!value) return "";
  if (value instanceof Date) return value.toISOString().slice(0, 10);
  if (typeof value === "string") {
    // Handle ISO strings that may include time
    return value.slice(0, 10);
  }
  return String(value).slice(0, 10);
}

export function dailyNotePath(date?: string): string {
  const d = date || today();
  return `daily/${d}.md`;
}

export function extractTitle(content: string): string {
  const match = content.match(/^#\s+(.+)$/m);
  return match ? match[1].trim() : "Untitled";
}

export function tagsToString(tags: string[]): string {
  return tags.filter(Boolean).join(",");
}

#!/usr/bin/env tsx
// remember.ts — Write a memory to the brain (markdown + index)
// Usage: tsx scripts/remember.ts --type person --file people/nik.md --section "Key Facts" --content "Prefers Deno over Node" --tags "nik,coding"
//        tsx scripts/remember.ts --type daily --content "Nik seemed energized today" --tags "mood"
//        tsx scripts/remember.ts --type projects --project dots --org nikbrunner --content "Refactored project dir structure" --tags "maintenance"

import { join } from "node:path";
import { parseArgs } from "node:util";
import { BrainStore } from "./store.js";
import { appendToSection, dailyNotePath, today, tagsToString, extractTitle } from "./markdown.js";
import { commitFile } from "./git.js";
import type { BrainFileType } from "./types.js";

const ROOT_DIR = join(import.meta.dirname, "..");
const DB_PATH = join(ROOT_DIR, "index", "memory.db");

interface RememberArgs {
  type: BrainFileType;
  file?: string;
  section?: string;
  content: string;
  tags: string;
  project?: string;
  org?: string;
  commit?: boolean;
}

function parseCliArgs(): RememberArgs {
  const { values } = parseArgs({
    args: process.argv.slice(2),
    options: {
      type: { type: "string", default: "daily" },
      file: { type: "string" },
      section: { type: "string", default: "Key Facts" },
      content: { type: "string" },
      tags: { type: "string", default: "" },
      project: { type: "string" },
      org: { type: "string", default: "nikbrunner" },
      commit: { type: "boolean", default: true },
    },
    allowPositionals: true,
  });

  // Support positional content argument
  const content = values.content || (values as Record<string, unknown>)._[0] as string;
  if (!content) {
    console.error("Error: --content required (or pass as positional argument)");
    process.exit(1);
  }

  return {
    type: (values.type || "daily") as BrainFileType,
    file: values.file as string | undefined,
    section: (values.section || "Key Facts") as string,
    content,
    tags: (values.tags || "") as string,
    project: values.project as string | undefined,
    org: (values.org || "nikbrunner") as string,
    commit: values.commit as boolean | undefined,
  };
}

async function remember(args: RememberArgs): Promise<void> {
  const store = new BrainStore(DB_PATH);

  // Determine the target file
  let filePath: string;
  if (args.file) {
    filePath = args.file;
  } else if (args.type === "daily") {
    filePath = dailyNotePath(today());
  } else if (args.type === "projects" && args.project) {
    filePath = `projects/${args.org}/${args.project}/${today()}.md`;
  } else {
    const slug = args.content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-");
    filePath = `${args.type}/${slug}.md`;
  }

  const tags = args.tags.split(",").map(t => t.trim()).filter(Boolean);

  // Write to markdown
  const updatedFile = appendToSection(
    filePath,
    args.section,
    args.content,
    {
      type: args.type,
      tags,
      updated: today(),
    }
  );

  // Update index
  const title = extractTitle(updatedFile.content);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type: updatedFile.frontmatter.type || args.type,
    tags: tagsToString(updatedFile.frontmatter.tags || tags),
    title,
    content: updatedFile.content,
    updated: updatedFile.frontmatter.updated || today(),
    indexed_at: new Date().toISOString(),
  });

  console.log(`Remembered in ${updatedFile.path}: ${args.content}`);
  store.close();

  if (args.commit) {
    commitFile(ROOT_DIR, updatedFile.path, args.content);
  }
}

// Allow programmatic use
export async function rememberMemory(
  type: BrainFileType,
  content: string,
  options?: { file?: string; section?: string; tags?: string[]; project?: string; org?: string; commit?: boolean }
): Promise<string> {
  const filePath = options?.file
    || (type === "daily" ? dailyNotePath(today())
    : (type === "projects" && options?.project)
      ? `projects/${options.org || "nikbrunner"}/${options.project}/${today()}.md`
      : `${type}/${content.slice(0, 40).toLowerCase().replace(/[^a-z0-9]+/g, "-")}.md`);
  const section = options?.section || "Key Facts";
  const tags = options?.tags || [];

  const updatedFile = appendToSection(filePath, section, content, { type, tags, updated: today() });

  const store = new BrainStore(DB_PATH);
  store.upsertFile({
    path: updatedFile.path,
    checksum: updatedFile.checksum,
    type,
    tags: tagsToString(tags),
    title: extractTitle(updatedFile.content),
    content: updatedFile.content,
    updated: today(),
    indexed_at: new Date().toISOString(),
  });
  store.close();

  if (options?.commit !== false) {
    commitFile(ROOT_DIR, updatedFile.path, content);
  }

  return updatedFile.path;
}

// CLI entry point
if (import.meta.url === `file://${process.argv[1]}` || process.argv[1]?.endsWith("/remember.ts")) {
  const args = parseCliArgs();
  remember(args).catch(err => {
    console.error("remember failed:", err);
    process.exit(1);
  });
}
